class stockalert_Page1 extends TabbedPage
{
	 protected function populateForm()
	{
		$this->addTabs();
		$fs = $this->form->addElement('fieldset')->setLabel('stockalert page 1');
		$buttonGroup = $fs->addElement('group'); 
		$buttonGroup->addElement('submit', $this->getButtonName('back'), array('value' => '<< Back')); 
		$buttonGroup->addElement('submit', $this->getButtonName('submit'), array('value' => 'Finish')); 
		$buttonGroup->addElement('submit', $this->getButtonName('next'), array('value' => 'Next >>')); 
		$this->setDefaultAction('submit', 'empty.gif');
		$this->addGlobalSubmit();
		$idstockalert = $fs->addElement('text', 'idstockalert', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Index' )
;
		$this->form->addDataSource(new HTML_QuickForm2_DataSource_Array(array( 'username' => $_SERVER['PHP_AUTH_USER'] ) ) );
		$username = $fs->addElement('text', 'username', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'User' )
			->addFilter( 'trim' )
			->addFilter( 'strtoupper' )
			->addRule('required', 'username Field Required' );
		$value1 = $fs->addElement('text', 'value1', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'First Criteria' )
			->addFilter( 'trim' )
			->addFilter( 'strtoupper' )
			->addRule('required', 'value1 Field Required' );
		$value2 = $fs->addElement('text', 'value2', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'Second Criteria' )
			->addFilter( 'trim' )
			->addFilter( 'strtoupper' )
			->addRule('required', 'value2 Field Required' );
		$runstatus = $fs->addElement('text', 'runstatus', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Run Status' )
;
	}
}
